var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"좋아. 방금 꽤 나쁘지 않았어.","JPN":"よし、今のは悪くなかったわ。","ENG":"Okay, it was pretty good.","TWN":"很好，剛剛還不錯！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"한 번 더 이 느낌을 살려서…….","JPN":"もう一度、さっきの感じで……","ENG":"Let’s try this one more time...","TWN":"再熟悉一下這個感覺……"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_OFFICE_QM","text":{"KOREA":"안 본 사이 실력이 상당히 느셨구만.","JPN":"見ない間に相当腕を上げましたね。","ENG":"Your skill has improved a lot since the last time I saw you.","TWN":"一段時間沒見，實力進步不少喔。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"이제는 정말 더 가르쳐 드릴 것도 없겠수다.","JPN":"もう教えることはなさそうです。","ENG":"It looks like you won’t need my teaching anymore.","TWN":"看來我已經沒什麼可以教你的囉。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아. 안녕하세요, 현수 씨.","JPN":"あ、こんにちは、ケンジさん。","ENG":"Oh, hello, Hyunsoo.","TWN":"喔！哈囉，賢秀。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"체육관에서 뵙는 건 오랜만이네요. 요즘도 일이 많이 바쁘신가 봐요.","JPN":"ジムでお会いするのは久しぶりですね。最近もお忙しいのですか？","ENG":"It’s been a while since I saw you last in the gym. You must be busy.","TWN":"上次在體育館見到你已經多久啦？你最近也很忙吧？"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"뭐 변변찮은 회사 다니는 사람들이 다 그렇지.","JPN":"まあ、しがない会社員はみんなそうでしょう。","ENG":"You know how it is.","TWN":"哎呀～一般在公司上班不就這麼回事嗎？大家都差不多啦。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"야근에, 잔업에, 주말 출근까지…….","JPN":"夜勤に、残業、週末出勤……","ENG":"Working overtime, extra work, weekend work...","TWN":"平日加班啦，週末加班啦……"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"정신 안 차리면 한 달이 어떻게 지나가는지도 모르거든.","JPN":"ぼけっとしてると、一か月なんて一瞬ですよ。","ENG":"I don’t even remember how the last month went by.","TWN":"常常一不注意，一個月咻一下就過去了呢。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"하하. 이거, 오랜만에 보는 사람한테 너무 푸념만 늘어 놓는 것 같군.","JPN":"はは。久々に会ったというのに、愚痴ばかりですまないね。","ENG":"Oh, I’m boring you, aren’t I?","TWN":"哈哈，你看我真是的，我們這麼久沒見，一見面就一直跟你抱怨。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아뇨. 회사원들은 어딜 가나 다 비슷비슷하죠.","JPN":"いえ、会社員なんてどこも似たようなものです。","ENG":"Not at all. I guess that’s just the life of an office worker.","TWN":"別這麼說，上班族的心情應該都差不多啦。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그래도 그 바쁜 와중에 검술 연습까지 하시고, 성실하시네요.","JPN":"でも、お忙しい中でも剣術の稽古をされているなんて、努力家なのですね。","ENG":"But still, I think it’s a great idea to work out, despite the busy schedule.","TWN":"不過你這麼忙還來練劍，很認真呢。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"어떠신가요? 몸이 녹슬지 않게 하려면 움직여 줘야죠?","JPN":"どうです？　身体が怠けないようにするには、動くのが一番でしょ？","ENG":"So, how’s your practice going? Shall we spar?","TWN":"如何？要試試我是否寶刀未老嗎？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"흐음……. 이제는 나보다 더 연습을 열심히 하시나 본데.","JPN":"うーん……今では私よりも稽古に励んでいるようですが。","ENG":"Oh, I see you’ve grown very passionate.","TWN":"嗯嗯……現在你可是練得比我還勤快呢。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"요즘 다시 재미를 붙였거든요. 계기는 이미지 메이킹이었지만요.","JPN":"最近また楽しいと思うようになったんです。きっかけはイメージメイキングでしたけど。","ENG":"Yes, it’s quite fun actually. Even though my initial motive was to build a positive image of myself.","TWN":"因為我最近又找回練劍的樂趣，雖然契機是因為要打造形象。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"하하. 처음 본 날이 생각나는군.","JPN":"はは、初めて会った日のことを思い出します。","ENG":"Yeah, I remember your first day.","TWN":"哈哈，我想起我們第一次見面的時候。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"연습 상대가 되어 달라더니 다짜고짜 진검을 뽑아들었지.","JPN":"稽古の相手をしてくれと、いきなり本物の剣を抜いてきましたよね。","ENG":"You asked me to spar holding a real sword out of nowhere.","TWN":"我問你可不可以當我的練習對象，結果你二話不說就掏出一把貨真價實的劍。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"부끄럽네요. 그 때는 용병이라면 다들 연습도 실전처럼 하는 줄 알았으니까요.","JPN":"お恥ずかしい。あの時は、傭兵はみんな稽古も実践のような形でやるものだと思っていましたので。","ENG":"That’s embarrassing. I thought mercenaries practiced with real weapons back then.","TWN":"真是不好意思，我當時候以為傭兵都是拿真的劍在練習的。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그래서, 대답은?","JPN":"それで、返事は？","ENG":"So, spar with me?","TWN":"所以你的回答是？"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"좋아. 까짓 거 한 판 하겠수다.","JPN":"いいですよ、やりましょう。","ENG":"Gladly.","TWN":"好！就來比劃一場吧！"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"다만, 아무리 고등급 카운터라도 칼 한 자루로 밥 벌어먹고 사는 사람을 쉽게 꺾을 수는 없을 거요.","JPN":"ただ、いくら高ランクカウンターでも、剣一本で食ってる人間を打ちのめすのは簡単ではないと思いますよ。","ENG":"But I make a living with my sword; you won’t beat me easily even if you’re a high-grade Counter.","TWN":"不過，就算你是很厲害的制裁者，好歹我也是靠著一把劍闖蕩到現在，不要以為可以輕易打倒我喔！"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};